class Solution {
    public int findTheLongestSubstring(String s) {
        int[] maskIndex = new int[32];
        Arrays.fill(maskIndex, -1);
        maskIndex[0] = 0;
        int mask = 0, maxLen = 0;
        int[] vowelBits = new int[26];
        vowelBits['a' - 'a'] = 1 << 0;
        vowelBits['e' - 'a'] = 1 << 1;
        vowelBits['i' - 'a'] = 1 << 2;
        vowelBits['o' - 'a'] = 1 << 3;
        vowelBits['u' - 'a'] = 1 << 4;

        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (vowelBits[c - 'a'] != 0) {
                mask ^= vowelBits[c - 'a'];
            }
            int index = mask;
            if (maskIndex[index] != -1) {
                maxLen = Math.max(maxLen, i + 1 - maskIndex[index]);
            } else {
                maskIndex[index] = i + 1;
            }
        }
        return maxLen;
    }
}

